USE [SecureAppDB];
GO

EXEC sp_msforeachtable 'ALTER TABLE ? NOCHECK CONSTRAINT ALL';

-- ==========================================
-- PARCHE: AGREGAR VALOR POR DEFECTO A CAJA
-- ==========================================
IF NOT EXISTS (SELECT * FROM sys.default_constraints WHERE parent_object_id = OBJECT_ID('SesionesTurno') AND parent_column_id = COLUMNPROPERTY(OBJECT_ID('SesionesTurno'), 'StuFechaApertura', 'ColumnId'))
BEGIN
    ALTER TABLE [dbo].[SesionesTurno] ADD CONSTRAINT DF_SesionesTurno_FechaApertura DEFAULT (GETDATE()) FOR [StuFechaApertura];
END

-- ==========================================
-- LIMPIAR TABLAS
-- ==========================================
DELETE FROM [PreciosEspecialesItems];
DELETE FROM [PreciosEspeciales];
DELETE FROM [PerfilesPrecios];
DELETE FROM [PreciosBase];
DELETE FROM [Articulos];
DELETE FROM [MetodosPagos];

SET IDENTITY_INSERT [Articulos] ON;
SET IDENTITY_INSERT [Articulos] OFF;


SET IDENTITY_INSERT [PerfilesPrecios] ON;
SET IDENTITY_INSERT [PerfilesPrecios] OFF;

SET IDENTITY_INSERT [PreciosEspeciales] ON;
SET IDENTITY_INSERT [PreciosEspeciales] OFF;

SET IDENTITY_INSERT [PreciosEspecialesItems] ON;
SET IDENTITY_INSERT [PreciosEspecialesItems] OFF;

-- ==========================================
-- METODOS DE PAGO
-- ==========================================
SET IDENTITY_INSERT [MetodosPagos] ON;
SET IDENTITY_INSERT [MetodosPagos] OFF;

EXEC sp_msforeachtable 'ALTER TABLE ? WITH CHECK CHECK CONSTRAINT ALL';
GO
